// Generating custom form class "LoginForm"
class LoginForm extends FormData {
  LoginForm({
    required CredentialsPage credentialsPage,
    required VerificationPage verificationPage,
  }) : _credentialsPage = credentialsPage,
       _verificationPage = verificationPage;

  // page properties
  final CredentialsPage _credentialsPage;
  final VerificationPage _verificationPage;

  late final LoginFormContext formContext = LoginFormContext(pages);

  CredentialsContext get credentialsPage => formContext.credentialsPage;
  VerificationContext get verificationPage => formContext.verificationPage;

  @override
  late final List<FormPage> pages = [
    FormPage(
      name: 'credentials',
      items: [
        InputData<String, String>(
          name: "email",
          validator: (String? input) =>
              _credentialsPage.emailInputData.validateEmail(formContext, input),
          onSubmit: (InputData<String, String> data) =>
              _credentialsPage.emailInputData.onSubmitEmail(formContext, data),
        ),
        InputData<String, String>(
          name: "password",
          validator: (String? input) => _credentialsPage.passwordInputData
              .validatePassword(formContext, input),
          onSubmit: (InputData<String, String> data) => _credentialsPage
              .passwordInputData
              .onSubmitPassword(formContext, data),
        ),
      ],
    ),

    FormPage(
      name: 'verification',
      items: [
        InputData<String, int>(
          name: "code",
          validator: (String? input) =>
              _verificationPage.codeInputData.validateCode(formContext, input),
          onSubmit: (InputData<String, int> data) =>
              _verificationPage.codeInputData.onSubmitCode(formContext, data),
        ),
      ],
    ),
  ];

  @override
  String get name => 'login-form';

  @override
  Stream<LoginForm> get stream => streamController.stream.map((e) => this);

  @override
  LoginForm copy() => throw Exception('cannot copy a generated FormData class');

  Future<void> submitCredentialsPage() async {
    final page = pages[_credentialsPage.pageIndex];
    for (var inputItem in page.items) {
      if (inputItem.isOptional) {
        continue;
      }
      if (inputItem.hasNoValue) {
        await inputItem.submit();
        // if still no value return;
        if (inputItem.hasNoValue) {
          return;
        }
      }
    }

    // when all inputData items of the page have a value then submit page
    await _credentialsPage.onSubmitPage(
      formContext,
      formContext.credentialsPage.submitResult,
      page.items[0].value,
      page.items[1].value,
    );

    if (formContext.credentialsPage.submitResult.hasFailure &&
        formContext.credentialsPage.submitResult.failure.type == null) {
      formContext.credentialsPage.submitResult.failure = formContext
          .credentialsPage
          .submitResult
          .failure
          .copyWith(type: FailureType.error);
    } else if (formContext.credentialsPage.submitResult.hasNoValue &&
        !formContext.credentialsPage.submitResult.hasFailure) {
      final message =
          '! No value or failure was set on submitResult data inside onSubmitPage argument callback for credentials page when it was called.';
      formContext.credentialsPage.submitResult.failure = Failure(
        message,
        type: FailureType.error,
      );
      CrystallineGlobalConfig.logger.log(
        CrystallineGlobalConfig.logger.redText(message),
      );
    }
  }

  Future<void> submitVerificationPage() async {
    final page = pages[_verificationPage.pageIndex];
    for (var inputItem in page.items) {
      if (inputItem.isOptional) {
        continue;
      }
      if (inputItem.hasNoValue) {
        await inputItem.submit();
        // if still no value return;
        if (inputItem.hasNoValue) {
          return;
        }
      }
    }

    // when all inputData items of the page have a value then submit page
    await _verificationPage.onSubmitPage(
      formContext,
      formContext.verificationPage.submitResult,
      page.items[0].value,
    );

    if (formContext.verificationPage.submitResult.hasFailure &&
        formContext.verificationPage.submitResult.failure.type == null) {
      formContext.verificationPage.submitResult.failure = formContext
          .verificationPage
          .submitResult
          .failure
          .copyWith(type: FailureType.error);
    } else if (formContext.verificationPage.submitResult.hasNoValue &&
        !formContext.verificationPage.submitResult.hasFailure) {
      final message =
          '! No value or failure was set on submitResult data inside onSubmitPage argument callback for verification page when it was called.';
      formContext.verificationPage.submitResult.failure = Failure(
        message,
        type: FailureType.error,
      );
      CrystallineGlobalConfig.logger.log(
        CrystallineGlobalConfig.logger.redText(message),
      );
    }
  }

  @override
  bool operator ==(Object other) {
    if (other is! LoginForm) return false;

    return runtimeType == other.runtimeType &&
        pages == other.pages &&
        ListEquality<InputData>().equals(items, other.items) &&
        operationOrNull == other.operationOrNull &&
        sideEffects == other.sideEffects &&
        failureOrNull == other.failureOrNull;
  }

  @override
  int get hashCode => Object.hashAll([
    pages,
    runtimeType,
    items,
    operationOrNull,
    failureOrNull,
    sideEffects.all,
  ]);
}

